kernel void dynproc_kernel(
    int pyramid_height,
    global const int* d_gpuWall,
    global int* d_gpuResult_src,
    global int* d_gpuResult_dst,
    int cols,
    int rows,
    int t_start,
    int borderCols,
    int theHalo,
    local int* local_src,
    local int* local_dst,
    global int* d_outputBuffer
)
{
    int col = get_global_id(0);

    if (col >= cols) return;

    // Load initial src values into local buffer
    local_src[col] = d_gpuResult_src[col];

    // Process each row in the pyramid
    for (int h = 0; h < pyramid_height; h++) {
        int current_row = t_start + h;
        if (current_row >= rows - 1) break;

        // Find minimum from neighbors in local_src
        int min = local_src[col];
        if (col > 0) {
            int left = local_src[col - 1];
            if (left < min) min = left;
        }
        if (col < cols - 1) {
            int right = local_src[col + 1];
            if (right < min) min = right;
        }

        // Store result in local_dst
        local_dst[col] = d_gpuWall[current_row * cols + col] + min;

        // Ensure all writes complete before next iteration
        barrier(CLK_LOCAL_MEM_FENCE);

        // Copy dst to src for next iteration
        local_src[col] = local_dst[col];
    }

    // Write final result
    d_gpuResult_dst[col] = local_src[col];
}
